function solve(code: string[], businessLine: string[], isActive: boolean[]): string[] {
    // Define the order of business lines
    const businessOrder: string[] = ["electronics", "grocery", "pharmacy", "restaurant"];

    // Filter valid coupons based on the conditions
    const validCoupons: { code: string; businessLine: string; isActive: boolean }[] = code
        .map((c, i) => ({
            code: c,
            businessLine: businessLine[i],
            isActive: isActive[i]
        }))
        .filter(coupon => {
            // Condition 1: code is not empty and only contains allowed characters
            const codeValid = c => {
                return c !== "" && /^[a-zA-Z0-9_]+$/.test(c);
            };

            // Condition 2: businessLine is valid
            const businessValid = b => businessOrder.includes(b);

            // Condition 3: isActive is true
            return codeValid(coupon.code) && businessValid(coupon.businessLine) && coupon.isActive;
        });

    // Sort the valid coupons first by businessLine order, then by code dictionary order
    validCoupons.sort((a, b) => {
        const businessIndexA = businessOrder.indexOf(a.businessLine);
        const businessIndexB = businessOrder.indexOf(b.businessLine);

        if (businessIndexA !== businessIndexB) {
            return businessIndexA - businessIndexB;
        }

        return a.code.localeCompare(b.code);
    });

    // Extract the codes from the sorted valid coupons
    return validCoupons.map(coupon => coupon.code);
}

